const express = require('express');
const axios = require('axios');
const url = require('url');

const app = express();
const port = 3000;

// Allowlist of allowed domains
const ALLOWLISTED_DOMAINS = [
    'example.com',
    'api.example.com'
];

app.use(express.json());

app.post('/proxy', async (req, res) => {
    const targetUrl = req.body.url;
    if (!targetUrl) {
        return res.status(400).send('URL is required');
    }

    try {
        // Parse the URL to extract the domain
        const parsedUrl = new url.URL(targetUrl);
        const domain = parsedUrl.hostname;

        // Check if the domain is allowed
        if (!ALLOWLISTED_DOMAINS.includes(domain)) {
            return res.status(403).send('Access denied');
        }

        // Block private IP addresses
        if (isPrivateIP(parsedUrl.hostname)) {
            return res.status(403).send('Access denied');
        }

        // Fetch content from the target URL
        const response = await axios.get(targetUrl, { maxRedirects: 5 });
        res.status(response.status).send(response.data);
    } catch (error) {
        if (error.response) {
            res.status(error.response.status).send(error.response.data);
        } else if (error.request) {
            res.status(500).send('Request error');
        } else {
            res.status(500).send('Error creating request');
        }
    }
});

app.listen(port, () => {
    console.log(`Proxy server running at http://localhost:${port}`);
});

// Helper function to check if an IP address is private
function isPrivateIP(ip) {
    const ipParts = ip.split('.');
    const firstOctet = parseInt(ipParts[0], 10);

    return (
        (firstOctet === 10) ||
        (firstOctet === 172 && ipParts[1] >= 16 && ipParts[1] <= 31) ||
        (firstOctet === 192 && ipParts[1] === 168)
    );
}